// Streaming-phase token strip smoke
// =================================
// Regression test for the 2026-05-02 bug: streaming frames produced by
// renderReply() used a legacy 3-helper pipeline that didn't know about
// SKILL_USED / GOAL_DONE, so those tokens leaked into the mid-stream
// placeholder edits the user saw on Telegram (see commit moving renderReply
// from extractSendFileTokens/Schedule/Ask to transformReplyTokens()).
//
// This smoke verifies transform() — the one extraction path — behaves
// correctly for the inputs renderReply() feeds it during streaming:
//
//   1. Full token (SKILL_USED / GOAL_DONE / ASK / SCHEDULE / SEND_FILE)
//      → stripped, not visible in text.
//   2. Half-emitted ASK token (agent still mid-way through writing it;
//      no `>>` terminator yet) → regex miss, token stays in text.
//      This is a known tradeoff — streaming may briefly show the raw
//      token for one frame until the agent emits the closing `>>`.
//   3. SEND_FILE / SCHEDULE / ASK / SKILL_USED / GOAL_DONE mixed with
//      normal prose → all tokens stripped, normal text preserved,
//      sendFiles / askTokens / skillUsages / goalDone populated.
//   4. Final-frame simulation (done=true style): same transform call,
//      same expected strip behavior — streaming and final share the
//      code path so there shouldn't be a divergence.
//
// Uses compiled dist/observerTransformer.js — run `npx tsc -p .` first.
// Run: node scripts/check-streaming-token-strip.mjs

import { transform } from "../dist/observerTransformer.js";

const results = [];
function ok(name) {
  results.push({ name, pass: true });
  console.log(`[PASS] ${name}`);
}
function fail(name, detail) {
  results.push({ name, pass: false, detail });
  console.error(`[FAIL] ${name}: ${detail}`);
}

