// Stub parsers matching the shape passed by renderReply() — for a streaming
// test we only care that SCHEDULE tokens get recognized and stripped; we
// don't actually register schedules here. `30s` is accepted as 30-second
// duration; everything else is null.
const streamParsers = {
  parseDuration: (raw) => {
    const m = /^(\d+)s$/.exec(raw);
    return m ? Number(m[1]) * 1000 : null;
  },
  parseAbsoluteTime: () => null,
  parseRecurrence: () => null,
  computeNextRunAt: () => null,
  now: () => 1_700_000_000_000,
};

// ───────────────────────────────────────────────────────────────────────
// 1. SKILL_USED — full token stripped in streaming frame
// ───────────────────────────────────────────────────────────────────────
{
  const raw = "Analyzing the problem.\n<<SKILL_USED:ms-agent-text-token-signaling|referenced signaling protocol>>";
  const r = transform(raw, streamParsers);
  if (r.text.includes("<<SKILL_USED:")) {
    fail("1. SKILL_USED stripped in streaming", `text still contains token: ${JSON.stringify(r.text)}`);
  } else if (r.text !== "Analyzing the problem.") {
    fail("1. SKILL_USED stripped in streaming", `expected clean prose, got: ${JSON.stringify(r.text)}`);
  } else if (r.skillUsages.length !== 1 || r.skillUsages[0].name !== "ms-agent-text-token-signaling") {
    fail("1. SKILL_USED stripped in streaming", `skillUsages mismatch: ${JSON.stringify(r.skillUsages)}`);
  } else {
    ok("1. SKILL_USED full token stripped, skill recorded");
  }

