// Draft render order smoke
// =========================
// Regression test for the 2026-07-10 draft streaming 顯示問題：
//
// Telegram client 對 draft 更新的動畫是「長度差」語意 —— 立即顯示新文字的
// 前 strlen(prev) 個字元，再淡入最後 max(0, strlen(new) - strlen(prev)) 個。
// renderReply() 把 tools/thinking 放頭部，新 tool 行完成時頭部插入字元，
// client 立即顯示的前綴就少掉 body 尾端同長度字元（使用者看到已顯示文字
// 倒退）。renderDraftReply() 改為 body → thinking → tools 排序，讓 draft
// 幀近似 append-only；並輸出 markdown 原文（rich_message.markdown 收
// markdown，不是 renderReply 的 HTML）。
//
// Uses compiled dist/telegram-ui.js — run `npx tsc -p .` first.
// Run: node scripts/check-draft-render.mjs

import { renderDraftReply } from "../dist/telegram-ui.js";

function assert(name, condition, detail = "") {
  if (!condition) {
    throw new Error(`FAIL: ${name}${detail ? `: ${detail}` : ""}`);
  }
  console.log(`ok - ${name}`);
}

const parsers = {
  parseDuration: () => null,
  parseAbsoluteTime: () => null,
  parseRecurrence: () => null,
  computeNextRunAt: () => null,
  now: () => 1_700_000_000_000,
};

const makeSession = ({ buffer = "", thinking = "", tools = [] } = {}) => ({
  buffer,
  thinkingBuffer: thinking,
  toolTimeline: tools,
  toolLog: [],
});

const tool = (name, elapsedMs) => ({ name, status: "completed", elapsedMs });

// ─── 1. 排序：body → thinking → tools ───

{
  const s = makeSession({
    buffer: "目前在驗證streaming",
    thinking: "Let me check the onChange callback.",
    tools: [tool("Read File", 2700), tool("Read File", 2600)],
  });
  const frame = renderDraftReply(s, parsers);
  assert("body 在最前面", frame.indexOf("目前在驗證streaming") === 0, frame);
  assert("thinking 在 body 之後", frame.indexOf("💭") > frame.indexOf("目前在驗證streaming"));
  assert("tools 在 thinking 之後", frame.indexOf("✅ Read File") > frame.indexOf("💭"));
}

// ─── 2. 頭部穩定：tools 增加不動 body 前綴（動畫倒退回歸重點） ───

{
  const base = {
    buffer: "目前在驗證streaming",
    thinking: "Let me check the onChange callback.",
  };
  const frame1 = renderDraftReply(
    makeSession({ ...base, tools: [tool("Read File", 2700), tool("Read File", 2600)] }),
    parsers,
  );
  const frame2 = renderDraftReply(
    makeSession({ ...base, tools: [tool("Read File", 2700), tool("Read File", 2600), tool("Terminal", 8100)] }),
    parsers,
  );
  // frame2 必須以 frame1 去掉 tools 段之前的所有內容開頭（共同前綴涵蓋完整 body）
  const bodyEnd = frame1.indexOf("💭");
  assert("tool 行增加後 body+cursor 前綴不變", frame2.startsWith(frame1.slice(0, bodyEnd)), frame2);
  assert("frame2 長度只增不減", frame2.length > frame1.length);
}

// ─── 3. body 追加 = 前綴延伸（tools/thinking 不變時整段共同前綴 ≥ 舊 body） ───

{
  const tools = [tool("Read File", 2700)];
  const frame1 = renderDraftReply(makeSession({ buffer: "回答第一段", tools }), parsers);
  const frame2 = renderDraftReply(makeSession({ buffer: "回答第一段，接著第二段", tools }), parsers);
  let common = 0;
  while (common < frame1.length && frame1[common] === frame2[common]) common++;
  assert("body 追加後共同前綴涵蓋舊 body", common >= "回答第一段".length, `common=${common}`);
}

// ─── 4. markdown 原文輸出（不是 HTML；& < > 不被 escape） ───

{
  const s = makeSession({ buffer: "**bold** & a<b 判斷" });
  const frame = renderDraftReply(s, parsers);
  assert("markdown 標記保留", frame.includes("**bold**"), frame);
  assert("& 不被 HTML escape", frame.includes("& a<b"), frame);
  assert("無 HTML 標籤混入", !/<\/?(b|i|code|blockquote|pre)>/.test(frame), frame);
}

// ─── 5. 全空 → 空字串（trySendDraft 送 text=undefined → server 原生 Thinking…） ───

{
  const frame = renderDraftReply(makeSession(), parsers);
  assert("全空回空字串", frame === "");
}

// ─── 6. 超長 body 截斷保尾 ───

{
  const long = "字".repeat(5000) + "結尾標記";
  const s = makeSession({ buffer: long, tools: [tool("Read File", 1000)] });
  const frame = renderDraftReply(s, parsers);
  assert("超長 body 頭部加省略號", frame.startsWith("…"), frame.slice(0, 20));
  assert("截斷保留 body 尾端", frame.includes("結尾標記"));
  assert("總長不超過 4096", frame.length <= 4096, `len=${frame.length}`);
}

// ─── 7. token 剝除與 renderReply 同路徑 ───

{
  const s = makeSession({ buffer: "正文內容\n<<SKILL_USED:some-skill|used it>>" });
  const frame = renderDraftReply(s, parsers);
  assert("SKILL_USED token 被剝除", !frame.includes("<<SKILL_USED"), frame);
  assert("正文保留", frame.includes("正文內容"));
}

console.log("\ndraft render smoke OK");

