/**
 * Errors where the agent's cloud backend aborted the response stream. These
 * are almost always worth retrying (network blip, TLS reset, 5xx from the
 * upstream provider). We detect by error code + message/data fingerprints,
 * since kiro-cli wraps them as generic JSON-RPC -32603 Internal error.
 */
function isTransientBackendError(err: unknown): boolean {
  if (!err || typeof err !== "object") return false;
  const e = err as { code?: number; message?: string; data?: unknown };
  if (e.code !== -32603) return false;
  const parts: string[] = [];
  if (typeof e.message === "string") parts.push(e.message);
  if (e.data !== undefined) {
    try {
      parts.push(typeof e.data === "string" ? e.data : JSON.stringify(e.data));
    } catch {
      /* ignore */
    }
  }
  const blob = parts.join(" ").toLowerCase();
  return (
    blob.includes("dispatch failure") ||
    blob.includes("response stream") ||
    blob.includes("timeout") ||
    blob.includes("connection reset") ||
    blob.includes("connection closed") ||
    blob.includes("broken pipe")
  );
}

