// Live probe: claude-agent-acp (nested SDK bumped to 0.3.206)
// initialize → session/new → dump model options → set model=claude-fable-5
import { spawn } from "node:child_process";

const ADAPTER = "C:\\Users\\jiunchiwang\\AppData\\Roaming\\npm\\node_modules\\@zed-industries\\claude-agent-acp\\dist\\index.js";

const child = spawn(process.execPath, [ADAPTER], {
  stdio: ["pipe", "pipe", "pipe"],
  cwd: "G:\\AI\\telegram-kiro-bridge-main",
});

let nextId = 1;
const pending = new Map();
let buf = "";

child.stdout.on("data", (d) => {
  buf += d.toString();
  let idx;
  while ((idx = buf.indexOf("\n")) >= 0) {
    const line = buf.slice(0, idx).trim();
    buf = buf.slice(idx + 1);
    if (!line) continue;
    let msg;
    try { msg = JSON.parse(line); } catch { console.log("[raw]", line.slice(0, 200)); continue; }
    if (msg.id !== undefined && pending.has(msg.id)) {
      const { resolve, reject } = pending.get(msg.id);
      pending.delete(msg.id);
      if (msg.error) reject(new Error(JSON.stringify(msg.error)));
      else resolve(msg.result);
    } else if (msg.method) {
      // agent-initiated request/notification — log short, auto-reply empty result to requests
      console.log("[agent→]", msg.method);
      if (msg.id !== undefined) {
        child.stdin.write(JSON.stringify({ jsonrpc: "2.0", id: msg.id, result: {} }) + "\n");
      }
    }
  }
});
child.stderr.on("data", (d) => console.error("[stderr]", d.toString().trim().slice(0, 300)));
child.on("exit", (c) => console.log("[exit]", c));

function call(method, params, timeoutMs = 60000) {
  const id = nextId++;
  child.stdin.write(JSON.stringify({ jsonrpc: "2.0", id, method, params }) + "\n");
  return new Promise((resolve, reject) => {
    const t = setTimeout(() => { pending.delete(id); reject(new Error(`${method} timeout`)); }, timeoutMs);
    pending.set(id, {
      resolve: (v) => { clearTimeout(t); resolve(v); },
      reject: (e) => { clearTimeout(t); reject(e); },
    });
  });
}

try {
  const init = await call("initialize", {
    protocolVersion: 1,
    clientCapabilities: { fs: { readTextFile: true, writeTextFile: true }, terminal: true },
    clientInfo: { name: "test-probe", title: "model probe", version: "0" },
  });
  console.log("initialize OK; agentCapabilities:", JSON.stringify(init.agentCapabilities ?? {}));

  const sess = await call("session/new", { cwd: "G:\\AI\\telegram-kiro-bridge-main", mcpServers: [] });
  console.log("sessionId:", sess.sessionId);
  const modelOpt = (sess.configOptions ?? []).find((o) => o.id === "model");
  const flat = (modelOpt?.options ?? []).flatMap((o) => (o.options ? o.options : [o]));
  console.log("current model:", modelOpt?.currentValue);
  console.log("available models:", flat.map((o) => o.value).join(", "));

  const set = await call("session/set_config_option", {
    sessionId: sess.sessionId,
    configId: "model",
    value: "claude-fable-5",
  });
  const after = (set.configOptions ?? []).find((o) => o.id === "model");
  console.log("after set → current model:", after?.currentValue);
} catch (e) {
  console.error("PROBE FAIL:", e.message);
} finally {
  child.kill();
  process.exit(0);
}

